#!/usr/bin/env python3
# [SYSTEM: LEGACY_TUI | STATUS: ARCHIVE | DO NOT EXECUTE]
"""
OpenCode CLI entry point when running as python -m opencode
"""

if __name__ == '__main__':
    try:
        from .cli import main
        main()
    except Exception as e:
        import sys, traceback, os
        err = f"[OpenCode] Fatal error: {e}\n"
        sys.stderr.write("\n" + err)
        traceback.print_exc()
        # Write to crash log in project root
        try:
            with open(os.path.join(os.getcwd(), 'crash_log.txt'), 'a') as f:
                f.write(err)
                traceback.print_exc(file=f)
        except Exception:
            pass
        sys.exit(1)
